#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X;
        scanf("%d", &X);
        if (X > 100) X -= 10;
        printf("%d\n", X);
    }
    return 0;
}

